fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    let mut P = vec![0; n+1];
    for i in 1..=n {
        P[i] = P[i-1] + nums[i-1];
    }

    let mut L = vec![0; n];
    L[0] = 0;
    for i in 1..n {
        if nums[i] > nums[i-1] {
            L[i] = L[i-1];
        } else {
            L[i] = i;
        }
    }

    let mut R = vec![0; n];
    R[n-1] = n-1;
    for i in (0..n-1).rev() {
        if nums[i] < nums[i+1] {
            R[i] = R[i+1];
        } else {
            R[i] = i;
        }
    }

    let mut D = vec![0; n];
    D[0] = 0;
    for i in 1..n {
        if nums[i] < nums[i-1] {
            D[i] = D[i-1];
        } else {
            D[i] = i;
        }
    }

    let size = n+1;
    if size == 0 {
        return 0;
    }
    let k_total = if size > 1 {
        (size as f64).log2().floor() as usize + 1
    } else {
        1
    };

    let mut st_min = vec![vec![0; k_total]; size];
    let mut st_max = vec![vec![0; k_total]; size];

    for i in 0..size {
        st_min[i][0] = P[i];
        st_max[i][0] = P[i];
    }

    for j in 1..k_total {
        let step = 1 << (j - 1);
        for i in 0..=size - (1 << j) {
            st_min[i][j] = std::cmp::min(st_min[i][j-1], st_min[i+step][j-1]);
            st_max[i][j] = std::cmp::max(st_max[i][j-1], st_max[i+step][j-1]);
        }
    }

    fn qmin(st: &Vec<Vec<i64>>, l: usize, r: usize) -> i64 {
        let len = r - l + 1;
        if len == 0 {
            return 0;
        }
        let shift = (len as f64).log2().floor() as usize;
        let mid = r - (1 << shift) + 1;
        std::cmp::min(st[l][shift], st[mid][shift])
    }

    fn qmax(st: &Vec<Vec<i64>>, l: usize, r: usize) -> i64 {
        let len = r - l + 1;
        if len == 0 {
            return 0;
        }
        let shift = (len as f64).log2().floor() as usize;
        let mid = r - (1 << shift) + 1;
        std::cmp::max(st[l][shift], st[mid][shift])
    }

    let mut ans = i64::MIN;
    for q in 1..n-1 {
        let p = D[q];
        if p == q {
            continue;
        }
        if L[p] > p - 1 {
            continue;
        }
        if R[q] < q + 1 {
            continue;
        }
        let min_left = qmin(&st_min, L[p], p-1);
        let max_right = qmax(&st_max, q+2, R[q]+1);
        ans = std::cmp::max(ans, max_right - min_left);
    }

    ans
}
