fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    if n < 4 {
        return 0;
    }
    let mut prefix = vec![0; n + 1];
    for i in 0..n {
        prefix[i + 1] = prefix[i] + nums[i];
    }

    let mut min_prefix_seg = vec![i64::MAX; n];
    for i in 1..n {
        if nums[i] > nums[i - 1] {
            if i == 1 {
                min_prefix_seg[i] = prefix[0];
            } else {
                min_prefix_seg[i] = min_prefix_seg[i - 1].min(prefix[i - 1]);
            }
        }
    }

    let mut max_prefix_seg = vec![i64::MIN; n];
    for i in (0..n).rev() {
        if i == n - 1 {
            continue;
        } else if i == n - 2 {
            if nums[i] < nums[i + 1] {
                max_prefix_seg[i] = prefix[i + 2];
            }
        } else {
            if nums[i] < nums[i + 1] {
                if max_prefix_seg[i + 1] == i64::MIN {
                    max_prefix_seg[i] = prefix[i + 2];
                } else {
                    max_prefix_seg[i] = max_prefix_seg[i + 1].max(prefix[i + 2]);
                }
            }
        }
    }

    let mut left_dec_start = vec![0; n];
    for i in 0..n {
        if i == 0 {
            left_dec_start[i] = i;
        } else {
            if nums[i] < nums[i - 1] {
                left_dec_start[i] = left_dec_start[i - 1];
            } else {
                left_dec_start[i] = i;
            }
        }
    }

    let max_k = (n as f64).log2().ceil() as usize + 1;
    let mut log = vec![0; n + 1];
    for i in 2..=n {
        log[i] = log[i >> 1] + 1;
    }

    if n == 0 {
        return 0;
    }

    let mut st = vec![vec![i64::MAX; n]; max_k];
    for i in 0..n {
        st[0][i] = min_prefix_seg[i];
    }

    for k in 1..max_k {
        let step = 1 << (k - 1);
        for i in 0..n {
            if i + step < n {
                st[k][i] = st[k - 1][i].min(st[k - 1][i + step]);
            } else {
                st[k][i] = st[k - 1][i];
            }
        }
    }

    let mut ans = i64::MIN;
    for q in 0..n {
        if max_prefix_seg[q] == i64::MIN {
            continue;
        }
        let start = left_dec_start[q];
        let end = if q >= 1 { q - 1 } else { 0 };
        if start > end {
            continue;
        }
        let k = log[end - start + 1];
        let min_val = st[k][start].min(st[k][end - (1 << k) + 1]);
        if min_val == i64::MAX {
            continue;
        }
        let candidate = max_prefix_seg[q] - min_val;
        if candidate > ans {
            ans = candidate;
        }
    }

    ans
}
